effect.shader:
void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st;
    if(screenSpace) {
        st = acScreenNorm;
        st.y = 1.0  - st.y;
        st -= 0.5;
        st.x *= acScreenSize.x/acScreenSize.y;
        st -= (position/1200.0);
    } else {
        st = ((vec2(acScreenNorm.x,1.0-acScreenNorm.y)*acScreenSize)-acLayerCenter)/length(acLayerSize)-(position/1200.0);
    }

    //st.y *= stretch;
    float a = angle * 0.0174533;
    st *= mat2(
        sin(a), -cos(a),
        cos(a), sin(a)
    );
    float px = floor(st.x*amount);
    float py = floor(st.y*amount/stretch);
    float p = step(mod(px+py,2.0),0.5);
    //p = smoothstep(0.5+smoothing/2.0,0.5,p)*smoothstep(0.0,smoothing/0.2,p);
    vec4 c = color * p;
    if( punchout ) {
        gl_FragColor = texColor * (1.0-p);
    } else {
        c *= texColor.a;
        gl_FragColor = c + (texColor*(1.0-c.a));
    }
}
